/**
 * latexhelper plugin for TinyMCE 8+
 * Open eClass 3.0 Compatibility
 */
(function() {
    "use strict";

    tinymce.PluginManager.add("latexhelper", function(editor, url) {

        const openDialog = () => {
            let selectedText = editor.selection.getContent({ format: "text" });
            selectedText = selectedText.replace(/^\\\(|\\\)$/g, "").replace(/^\[m\]|\[\/m\]$/g, "");

            const lang = window.latexHelperLang || { title: "Insert LaTeX" };

            editor.windowManager.openUrl({
                title: lang.title,
                url: url + "/dialog.html",
                width: 900,
                height: 700,
                onMessage: (api, message) => {

                    if (message.mceAction === "latexhelper-insert") {
                        let content = message.content.trim();

                        content = content.replace(/<\/?[^>]+(>|$)/g, "");

                        if (content !== "") {
                            editor.insertContent("\\(" + content + "\\)");
                        }
                        api.close();
                    }

                    if (message.mceAction === "latexhelper-cancel") {
                        api.close();
                    }

                    if (message.mceAction === "ready") {
                        api.sendMessage({
                            mceAction: "latexhelper-initial-data",
                            content: selectedText,
                            latexLang: window.latexHelperLang
                        });
                    }
                }
            });
        };

        editor.ui.registry.addIcon('latexhelper-icon', '<svg width="24" height="24" x="0" y="0" viewBox="0 0 512 512" style="enable-background:new 0 0 512 512" xml:space="preserve" class=""><g><path d="M263.507 62.967C265.179 51.833 272.833 40 283.729 40c11.028 0 20 8.972 20 20h40c0-33.084-26.916-60-60-60-33.629 0-55.527 28.691-59.784 57.073L211.083 144h-61.354v40h55.436l-39.22 265.073-.116.937c-1.063 10.62-9.393 21.99-20.1 21.99-11.028 0-20-8.972-20-20h-40c0 33.084 26.916 60 60 60 33.661 0 56.771-29.141 59.848-57.496L245.6 184h60.129v-40h-54.211l11.989-81.033zM426.271 248h-48.035l-25.987 39.085L334.923 248H291.17l34.827 78.569L270.523 410h48.035l26.652-40.085L362.979 410h43.753l-35.27-79.569z" fill="#000000" opacity="1" data-original="#000000" class=""></path></g></svg>');

        editor.ui.registry.addButton("latexhelper", {
            icon: 'latexhelper-icon',
            // text: "LaTeX",
            tooltip: "Insert Math",
            onAction: openDialog
        });

        editor.ui.registry.addMenuItem("latexhelper", {
            text: "LaTeX Math",
            icon: "latex",
            onAction: openDialog
        });

        return {
            getMetadata: function() {
                return {
                    name: "LaTeX Helper (v8 Compatible)",
                    url: "https://www.openeclass.org"
                };
            }
        };
    });
})();